build for javascript backend

database is local memory

create a CountLog table:
  count_val, default 0

when user calls GET /api/count:
  logs = get all CountLog
  if length of logs is 0:
    send back { count: 0 }
  latest = last of logs
  send back { count: latest's count_val }

when user calls POST /api/increment:
  logs = get all CountLog
  if length of logs is 0:
    first_log = { count_val: 1 }
    save first_log as new CountLog
    send back { count: 1 }
  latest = last of logs
  new_count = latest's count_val + 1
  new_log = { count_val: new_count }
  save new_log as new CountLog
  send back { count: new_count }

when user calls POST /api/reset:
  reset_log = { count_val: 0 }
  save reset_log as new CountLog
  send back { count: 0 }
